mapper.select:
select id, code, name, realm_type_id as realmTypeId, login_url as loginUrl, login_page_id as loginPageId, auth_policy_id as authPolicyId, status, create_time, update_time from realm
and `name` like concat('%', #{realmPageRequest.name}, '%')
and `code` = #{realmPageRequest.code}
and `status` = #{realmPageRequest.status}
and realm_type_id = #{realmPageRequest.realmTypeId}
order by update_time desc, create_time desc
